class Solution {
    int m, n;
    boolean[][] matrix;
    Random random;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        this.matrix = new boolean[m][n];
        this.random = new Random();
    }

    public int[] flip() {
        while (true) {
            int i = random.nextInt(m);
            int j = random.nextInt(n);
            if (!matrix[i][j]) {
                matrix[i][j] = true;
                return new int[]{i, j};
            }
        }
    }

    public void reset() {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                matrix[i][j] = false;
            }
        }
    }
}
